// ============================================================================
// 1) 回旋月刃 — boomerang crescent that flies out, curves back through foes.
//    Custom blade entities in inst.st (true out-and-back; repeat hits gated).
//    Tier 2.
// ============================================================================
Weapons.register({
  id: 'wc_boomerang', name: '回旋月刃', icon: 'weapon_wc_boomerang', tier: 2, weight: 7, maxLevel: 6,
  cooldown: (l) => Math.max(0.8, 1.5 - l * 0.1),
  fire(world, p, inst) {
    const l = inst.level;
    const count = 1 + Math.floor(l / 2) + (p.stats.projCountAdd || 0);
    const reach = (70 + l * 11) * (p.stats.area || 1);
    const tgt = wcAim(world, p.x, p.y, 1)[0];
    const base = tgt ? Math.atan2(tgt.y - p.y, tgt.x - p.x) : wcFace(p);
    inst.st.blades = inst.st.blades || [];
    for (let i = 0; i < count; i++) {
      const a = base + (count > 1 ? (i / (count - 1) - 0.5) * 0.55 : 0);
      inst.st.blades.push({ x: p.x, y: p.y, a, t: 0, dur: 1.05, reach, base: 10 + l * 3.4, hits: new Map(), spin: 0 });
    }
    Sfx.play('shoot');
  },
  update(world, p, inst, dt) {
    const blades = inst.st.blades; if (!blades || !blades.length) return;
    for (let i = blades.length - 1; i >= 0; i--) {
      const b = blades[i];
      b.t += dt; b.spin += dt * 16;
      const k = Math.min(1, b.t / b.dur);
      const out = Math.sin(k * Math.PI) * b.reach;     // 0 -> reach -> 0
      if (k > 0.5) { const back = Math.atan2(p.y - b.y, p.x - b.x); b.a = wcLerpA(b.a, back, dt * 3.0); }
      b.x = p.x + Math.cos(b.a) * out;
      b.y = p.y + Math.sin(b.a) * out;
      const R = 9;
      for (const e of world.enemies) {
        if (e.dead || e.spawnT > 0) continue;
        if (dist2(b.x, b.y, e.x, e.y) < (e.radius + R) * (e.radius + R)) {
          const last = b.hits.get(e) || 0;
          if (world.time > last) {
            b.hits.set(e, world.time + 0.3);
            const { dmg, crit } = wcRoll(p, b.base);
            const kb = 24 * (p.stats.knockbackMult || 1);
            e.hurt(dmg, Math.cos(b.a) * kb, Math.sin(b.a) * kb, world, crit);
          }
        }
      }
      if (b.t >= b.dur) blades.splice(i, 1);
    }
  },
  draw(world, p, inst) {
    const blades = inst.st.blades; if (!blades) return;
    const sp = getSprite('wc_fx_boomerang');
    for (const b of blades) {
      glowWorld(b.x, b.y, 7, P.steelL, 0.4);
      drawSprite(sp.frames[0], b.x, b.y, { ax: sp.ax, ay: sp.ay, rot: b.spin });
    }
  },
  levelDesc: (l) => '月刃 ' + (1 + Math.floor(l / 2)) + '・單擊 ' + ((10 + l * 3.4) | 0) + '・往返切削',
  desc: '擲出回旋月刃飛出再折返，沿途反覆切削敵人。',
});

// ============================================================================
// 2) 散華弩 — spread cone of piercing shards toward nearest/facing.
