// ============================================================================
Weapons.register({
  id: 'wc_cone', name: '散華弩', icon: 'weapon_wc_cone', tier: 1, weight: 8, maxLevel: 6,
  cooldown: (l) => Math.max(0.5, 0.95 - l * 0.06),
  fire(world, p, inst) {
    const l = inst.level;
    const count = 3 + Math.floor(l * 0.8) + (p.stats.projCountAdd || 0);
    const spread = 0.55 + l * 0.04;
    const tgt = wcAim(world, p.x, p.y, 1)[0];
    const base = tgt ? Math.atan2(tgt.y - p.y, tgt.x - p.x) : wcFace(p);
    const sp = 230 * (p.stats.projSpeedMult || 1);
    for (let i = 0; i < count; i++) {
      const a = base + (count > 1 ? (i / (count - 1) - 0.5) * spread : 0) + (Math.random() - 0.5) * 0.05;
      const { dmg, crit } = wcRoll(p, 6 + l * 2.0);
      world.addProjectile(new Projectile({
        x: p.x, y: p.y, vx: Math.cos(a) * sp, vy: Math.sin(a) * sp,
        damage: dmg, crit, faction: 'player', sprite: 'wc_fx_shard', color: P.greenL,
        radius: 2.6, pierce: Math.floor(l / 3) + (p.stats.pierceAdd || 0), life: 0.7, knockback: 12,
      }));
    }
    world.particles.burst(p.x, p.y, 4, { angle: base, spread: 0.5, speed: 80, color: [P.greenL, P.white], size: 1.4, life: 0.14, glow: true });
    Sfx.play('shoot');
  },
  levelDesc: (l) => '飛矢 ' + (3 + Math.floor(l * 0.8)) + '・穿透 ' + Math.floor(l / 3) + '・傷害 ' + ((6 + l * 2.0) | 0),
  desc: '朝最近敵人扇形連射穿刺飛矢，橫掃成排目標。',
});

// ============================================================================
// 3) 聚能光束 — locked continuous beam; hitscan ticks along a line segment.
//    Tier 3.
// ============================================================================
Weapons.register({
  id: 'wc_beam', name: '聚能光束', icon: 'weapon_wc_beam', tier: 3, weight: 6, maxLevel: 6,
  update(world, p, inst, dt) {
    const l = inst.level;
    inst.st.cd = inst.st.cd || new Map();
    inst.st.t = (inst.st.t || 0) - dt;
    const range = WC_BAL.AIM_RANGE + l * 10;
    if (inst.st.t <= 0) {
      inst.st.t = 0.12;                                  // damage tick rate
      const tgt = wcAim(world, p.x, p.y, 1)[0];
      const a = tgt ? Math.atan2(tgt.y - p.y, tgt.x - p.x) : wcFace(p);
      const ex = p.x + Math.cos(a) * range, ey = p.y + Math.sin(a) * range;
      inst.st.shot = { x0: p.x, y0: p.y, x1: ex, y1: ey, a };
      world.addBeam(p.x, p.y, ex, ey, P.iceD);
      const halfW = 5 + l * 0.5;                          // beam half-width
      for (const e of world.enemies) {
        if (e.dead || e.spawnT > 0) continue;
        const t = Math.max(0, Math.min(1, ((e.x - p.x) * Math.cos(a) + (e.y - p.y) * Math.sin(a)) / range));
        const px = p.x + (ex - p.x) * t, py = p.y + (ey - p.y) * t;
        if (dist2(px, py, e.x, e.y) < (halfW + e.radius) * (halfW + e.radius)) {
          const last = inst.st.cd.get(e) || 0;
          if (world.time >= last) {
            inst.st.cd.set(e, world.time + 0.1);
            const { dmg, crit } = wcRoll(p, 7 + l * 2.0);
            e.hurt(dmg, Math.cos(a) * 6, Math.sin(a) * 6, world, crit);
            if (Math.random() < 0.5) world.particles.spawn({ x: e.x, y: e.y, life: 0.2, size: 2, color: P.iceD, glow: true });
          }
        }
      }
    } else {
      // keep the visible beam following the current aim between damage ticks
      const s = inst.st.shot;
      if (s) world.addBeam(p.x, p.y, p.x + Math.cos(s.a) * range, p.y + Math.sin(s.a) * range, P.iceD);
    }
  },
  draw(world, p, inst) {
    const s = inst.st.shot; if (!s) return;
    glowWorld(s.x1, s.y1, 7, P.blueL, 0.5);
    glowWorld((s.x0 + s.x1) / 2, (s.y0 + s.y1) / 2, 6, P.iceD, 0.22);
  },
  levelDesc: (l) => '每跳 ' + ((7 + l * 2.0) | 0) + '・射程 ' + (WC_BAL.AIM_RANGE + l * 10) + '・持續灼燒',
  desc: '鎖定最近敵人持續灼燒的聚能光束，貫穿一線上的所有敵人。',
});

// ============================================================================
// 4) 碎地尖刺 — erupts a line of ground spikes toward the nearest enemy.
//    Spikes telegraph briefly, then deal one area hit; tracked in inst.st.
//    Tier 2.
// ============================================================================
Weapons.register({
  id: 'wc_spikes', name: '碎地尖刺', icon: 'weapon_wc_spikes', tier: 2, weight: 6, maxLevel: 6,
  cooldown: (l) => Math.max(0.9, 1.7 - l * 0.12),
  fire(world, p, inst) {
    const l = inst.level;
    inst.st.spikes = inst.st.spikes || [];
    const tgt = wcAim(world, p.x, p.y, 1)[0];
    const a = tgt ? Math.atan2(tgt.y - p.y, tgt.x - p.x) : wcFace(p);
    const segs = 3 + Math.floor(l / 2);
    const step = 22 + l * 1.5;
    const start = 14;
    const radius = (15 + l * 1.6) * (p.stats.area || 1);
    for (let i = 0; i < segs; i++) {
      const d = start + i * step;
      const sx = p.x + Math.cos(a) * d, sy = p.y + Math.sin(a) * d;
      if (world.solidAt(sx, sy)) break;                  // stop at walls
      inst.st.spikes.push({ x: sx, y: sy, warn: 0.18 + i * 0.05, life: 0.45, hit: false, r: radius, dmg: 12 + l * 4.5, a });
    }
    Sfx.play('shoot');
  },
  update(world, p, inst, dt) {
    const spikes = inst.st.spikes; if (!spikes || !spikes.length) return;
    for (let i = spikes.length - 1; i >= 0; i--) {
      const s = spikes[i];
      s.warn -= dt;
      if (s.warn <= 0 && !s.hit) {
        s.hit = true;
        const { dmg, crit } = wcRoll(p, s.dmg);
        world.dealAreaDamage(s.x, s.y, s.r, dmg, { knockback: 70 * (p.stats.knockbackMult || 1), crit });
        world.particles.burst(s.x, s.y, 6, { speed: 70, color: [P.ice, P.white], size: 2, life: 0.25, glow: true });
      }
      if (s.warn <= -s.life) spikes.splice(i, 1);
    }
  },
  draw(world, p, inst) {
    const spikes = inst.st.spikes; if (!spikes) return;
    const sp = getSprite('wc_fx_spike');
    for (const s of spikes) {
      if (!s.hit) {
        // telegraph: faint marker before eruption
        fillCircleWorld(s.x, s.y, s.r * 0.6, withAlpha(P.iceD, 0.10));
      } else {
        const k = Math.max(0, Math.min(1, (s.life + s.warn) / s.life));   // 1 -> 0 fade
        glowWorld(s.x, s.y, 8, P.ice, 0.35 * k);
        drawSprite(sp.frames[0], s.x, s.y, { ax: sp.ax, ay: sp.ay, scale: 0.7 + k * 0.5 });
      }
    }
  },
  levelDesc: (l) => '尖刺 ' + (3 + Math.floor(l / 2)) + '・單擊 ' + ((12 + l * 4.5) | 0) + '・線狀爆發',
  desc: '朝最近敵人方向掀起一排碎地尖刺，貫穿地面造成線狀重創。',
});

// ============================================================================
// 5) 跳躍流星 — ricochet pearl that bounces to the next nearest enemy on hit.
//    Tier 2.
// ============================================================================
Weapons.register({
  id: 'wc_ricochet', name: '跳躍流星', icon: 'weapon_wc_ricochet', tier: 2, weight: 7, maxLevel: 6,
  cooldown: (l) => Math.max(0.55, 1.15 - l * 0.09),
  fire(world, p, inst) {
    const l = inst.level;
    const shots = 1 + Math.floor(l / 3) + (p.stats.projCountAdd || 0);
    const hops = 2 + l;
    const base = 9 + l * 3.0;
    const targets = wcAim(world, p.x, p.y, shots);
    const sp = 245 * (p.stats.projSpeedMult || 1);
    for (let s = 0; s < shots; s++) {
      const t = targets.length ? targets[s % targets.length] : null;
      const a = t ? Math.atan2(t.y - p.y, t.x - p.x) : wcFace(p) + (s - shots / 2) * 0.25;
      const { dmg, crit } = wcRoll(p, base);
      world.addProjectile(wcMakePearl(p, p.x, p.y, a, sp, dmg, crit, hops, base));
    }
    Sfx.play('shoot');
  },
  levelDesc: (l) => '流星 ' + (1 + Math.floor(l / 3)) + '・彈跳 ' + (2 + l) + ' 次・傷害 ' + ((9 + l * 3.0) | 0),
  desc: '射出跳躍流星，命中後自動彈向下一個最近的敵人連環打擊。',
});
function wcMakePearl(p, x, y, a, sp, dmg, crit, hops, base) {
  return new Projectile({
    x, y, vx: Math.cos(a) * sp, vy: Math.sin(a) * sp,
    damage: dmg, crit, faction: 'player', sprite: 'wc_fx_pearl', color: P.gold,
    radius: 3.2, pierce: 0, life: 1.3, knockback: 12,
    onHit(target, world) {
      if (hops <= 0) return;
      let best = null, bd = 200 * 200;
      for (const e of world.enemies) {
        if (e.dead || e.spawnT > 0 || e === target) continue;
        const d = dist2(target.x, target.y, e.x, e.y);
        if (d < bd) { bd = d; best = e; }
      }
      if (!best) return;
      const na = Math.atan2(best.y - target.y, best.x - target.x);
      const { dmg: nd, crit: nc } = wcRoll(p, base * 0.9);
      const nb = wcMakePearl(p, target.x, target.y, na, sp, nd, nc, hops - 1, base);
      nb.hitSet.add(target);
      world.addProjectile(nb);
      world.particles.spawn({ x: target.x, y: target.y, life: 0.18, size: 2.4, color: P.gold, glow: true });
    },
  });
}

// ============================================================================
// 6) 守護砲塔 — orbiting turret that tracks foes and fires homing bolts.
//    The turret orbits the player; auto-aims the nearest enemy on a cadence.
//    Tier 3.
// ============================================================================
Weapons.register({
  id: 'wc_turret', name: '守護砲塔', icon: 'weapon_wc_turret', tier: 3, weight: 6, maxLevel: 6,
  update(world, p, inst, dt) {
    const l = inst.level;
    const n = 1 + Math.floor((l - 1) / 3);               // 1 -> up to 2 turrets
    const R = (34 + l * 2) * (p.stats.area || 1);
    inst.st.a = (inst.st.a || 0) + dt * 1.4;             // orbit angle
    inst.st.t = (inst.st.t || 0) - dt;
    inst.st.aim = inst.st.aim || [];
    inst.st.turrets = [];
    const fire = inst.st.t <= 0;
    if (fire) inst.st.t = Math.max(0.45, 0.9 - l * 0.06);
    for (let i = 0; i < n; i++) {
      const oa = inst.st.a + i / n * TAU;
      const ox = p.x + Math.cos(oa) * R, oy = p.y + Math.sin(oa) * R;
      // smooth-track the nearest enemy from the turret's position
      const tgt = wcAim(world, ox, oy, 1)[0];
      const want = tgt ? Math.atan2(tgt.y - oy, tgt.x - ox) : oa;
      inst.st.aim[i] = wcLerpA(inst.st.aim[i] != null ? inst.st.aim[i] : want, want, dt * 8);
      inst.st.turrets.push({ x: ox, y: oy, a: inst.st.aim[i] });
      if (fire && tgt) {
        const a = inst.st.aim[i];
        const { dmg, crit } = wcRoll(p, 8 + l * 3.0);
        const sp = 240 * (p.stats.projSpeedMult || 1);
        world.addProjectile(new Projectile({
          x: ox, y: oy, vx: Math.cos(a) * sp, vy: Math.sin(a) * sp,
          damage: dmg, crit, faction: 'player', sprite: 'wc_bolt_turret', color: P.purpleL,
          radius: 3, pierce: Math.floor(l / 4) + (p.stats.pierceAdd || 0), life: 1.1, knockback: 14,
          homing: 2.2 + (p.stats.homing || 0),
        }));
        world.particles.spawn({ x: ox, y: oy, life: 0.16, size: 1.8, color: P.purpleL, glow: true });
        if (i === 0) Sfx.play('shoot');
      }
    }
  },
  draw(world, p, inst) {
    const turrets = inst.st.turrets; if (!turrets) return;
    const sp = getSprite('wc_fx_turret');
    for (const t of turrets) {
      glowWorld(t.x, t.y, 7, P.purpleL, 0.35);
      drawSprite(sp.frames[0], t.x, t.y, { ax: sp.ax, ay: sp.ay, rot: t.a });
    }
  },
  levelDesc: (l) => '砲塔 ' + (1 + Math.floor((l - 1) / 3)) + '・每發 ' + ((8 + l * 3.0) | 0) + '・自動追蹤',
  desc: '召喚環繞自身的守護砲塔，自動鎖定並射出追蹤砲彈。',
});

